// Build DVI lookup table keyed by region_id with interpolation points
export const DVI_LOOKUP = {};
REGIONS_GEOJSON.features.forEach(f => {
  const rid = f.properties.region_id;
  const n = f.properties.region_name;
  const entries = DVI_RAW.filter(d => d.region === n);
  const pts = [{ year:1990, dvi:0 }];
  entries.forEach(e => {
    const endYear = parseInt(e.period.split("-")[1]);
    pts.push({ year:endYear, dvi:e.dvi });
  });
  // Interpolate a 2023 point for backward compatibility
  if (!pts.find(p=>p.year===2023)){
    const p2020 = pts.find(p=>p.year===2020);
    const p2025 = pts.find(p=>p.year===2025);
    if (p2020 && p2025) {
      const t = (2023 - 2020) / (2025 - 2020);
      pts.push({ year:2023, dvi:+(p2020.dvi + t * (p2025.dvi - p2020.dvi)).toFixed(1) });
    } else if (p2020) {
      pts.push({ year:2023, dvi:+(p2020.dvi * 0.96).toFixed(1) });
    }
  }
  DVI_LOOKUP[rid] = _.sortBy(pts,"year");
});
